// ── Frame Timestamp Calculator ──────────────────────────────────────────
// $input = Cloudinary Admin API response (per video)
// Duration source priority:
//   1. item.json.duration          — present when Cloudinary processes video codec
//   2. item.json.media_metadata.Duration — fallback string from ?media_metadata=true
// $('Read Pending Rows').item.json = original Google Sheets row (paired by index)

function calculateFrameTimestamps(duration) {
  duration = Math.floor(duration);

  if (duration < 8) {
    const mid = Math.floor(duration / 2);
    return [...new Set([0, mid, Math.max(0, duration - 1)])].sort((a, b) => a - b);
  }

  let interval;
  if (duration <= 15)      interval = 3;
  else if (duration <= 30) interval = 5;
  else if (duration <= 60) interval = 7;
  else                     interval = 10;

  const anchors = [0, 3, duration - 1];
  const middle = [];
  for (let t = 5; t <= duration - 2; t += interval) middle.push(t);

  let timestamps = [...new Set([...anchors, ...middle])].sort((a, b) => a - b);

  if (timestamps.length > 12) {
    const last = timestamps[timestamps.length - 1];
    timestamps = timestamps.slice(0, 11);
    if (!timestamps.includes(last)) timestamps.push(last);
  }

  return timestamps;
}

const results = [];

for (const item of $input.all()) {
  const sheets = $('Read Pending Rows').item.json;

  const duration =
    Number(item.json.duration) ||
    Number(item.json.media_metadata?.Duration) ||
    0;

  const timestamps  = duration > 0 ? calculateFrameTimestamps(duration) : [];

  results.push({
    json: {
      ad_id:       sheets.ad_id,
      video_url:   sheets.video_url,
      script:      sheets.script,
      success:     sheets.success,
      status:      sheets.status,
      duration,
      timestamps,
      frame_count: timestamps.length,
    }
  });
}

return results;

// ── Split timestamps array into one item per frame ────────────────────────
// Input:  single item with timestamps[] array
// Output: N items, one per timestamp, each carrying frame_url + full context

const item = $input.first().json;

const results = item.timestamps.map(ts => ({
  json: {
    ad_id:       item.ad_id,
    video_url:   item.video_url,
    script:      item.script,
    success:     item.success,
    status:      item.status,
    duration:    item.duration,
    timestamps:  item.timestamps,
    frame_count: item.frame_count,
    timestamp:   ts,
    frame_url:   `https://res.cloudinary.com/YOUR_CLOUDINARY_CLOUD_NAME/video/upload/so_${ts}/${item.video_url}.jpg`,
  }
}));

return results;

// ── Collect frame URLs after loop ─────────────────────────────────────────
// $input items = HTTP responses (binary JPEG, one per frame)
// $('Split Timestamps').all() = original items with frame_url strings

const splitItems = $('Split Timestamps').all();
const frame_urls = splitItems.map(item => item.json.frame_url);
const ctx = splitItems[0].json;

return [{
  json: {
    ad_id:       ctx.ad_id,
    video_url:   ctx.video_url,
    script:      ctx.script,
    success:     ctx.success,
    status:      ctx.status,
    duration:    ctx.duration,
    timestamps:  ctx.timestamps,
    frame_count: ctx.frame_count,
    frame_urls:  frame_urls,
  }
}];

// ── Build Claude Vision API request body ─────────────────────────────────
const item = $input.first().json;

const VISION_PROMPT = `You are an expert video analyst for a performance marketing team.

You will be shown between 6 and 12 frames from a single advertisement video,
sampled at regular intervals from start to finish.
Frames are ordered chronologically. The first 2 frames are the opening/hook.
The last frame is the closing. All others are middle frames.
Analyze all frames together as a complete narrative before extracting attributes.

Respond ONLY in valid JSON. No explanation, no preamble, no markdown.

{
  "hook_type": "question" / "bold_statement" / "visual_shock" / "person_speaking" / "text_only",
  "face_in_hook": true/false,
  "eye_contact_in_hook": true/false,
  "scene_setup": "person_to_cam" / "skit" / "skit_p2c" / "b_roll" / "b_roll_long",
  "subtitle_present": true/false
}

Rules:
- Use null for any attribute you cannot determine with reasonable confidence
- hook_type and face_in_hook must be based on the FIRST TWO frames only`;

const imageBlocks = item.frame_urls.map(url => ({
  type: 'image',
  source: { type: 'url', url }
}));

return [{
  json: {
    ad_id:       item.ad_id,
    video_url:   item.video_url,
    script:      item.script,
    success:     item.success,
    status:      item.status,
    duration:    item.duration,
    timestamps:  item.timestamps,
    frame_count: item.frame_count,
    frame_urls:  item.frame_urls,
    request_body: {
      model: 'claude-sonnet-4-6',
      max_tokens: 1024,
      messages: [{
        role: 'user',
        content: [
          ...imageBlocks,
          { type: 'text', text: VISION_PROMPT }
        ]
      }]
    }
  }
}];

// ── Build Claude Text API request body ──────────────────────────────────
const ctx = $('Build Vision Payload').first().json;

const SCRIPT_PROMPT = `You are an expert advertising analyst for a performance marketing team.

You will be given the pre-written script of a video advertisement.
The script may be in Hindi, English, or Hinglish (code-mixed).

Respond ONLY in valid JSON. No explanation, no preamble, no markdown.

SCRIPT:
"""
${ctx.script}
"""

{
  "emotional_tone": "urgency" / "fear" / "aspiration" / "humor" / "trust" / "empathy",
  "hook_addresses_pain": true/false,
  "social_proof_present": true/false,
  "cta_type": "download_app" / "check_score" / "call_now" / "visit_website" / "none",
  "language_primary": "hindi" / "english" / "hinglish"
}

Rules:
- If you cannot determine an attribute, use null
- emotional_tone: pick the single dominant tone`;

return [{
  json: {
    ad_id:       ctx.ad_id,
    video_url:   ctx.video_url,
    script:      ctx.script,
    success:     ctx.success,
    status:      ctx.status,
    duration:    ctx.duration,
    timestamps:  ctx.timestamps,
    frame_count: ctx.frame_count,
    frame_urls:  ctx.frame_urls,
    request_body: {
      model: 'claude-sonnet-4-6',
      max_tokens: 1024,
      messages: [{
        role: 'user',
        content: SCRIPT_PROMPT
      }]
    }
  }
}];

// ── Merge & Validate ──────────────────────────────────────────────────────────
function parseClaudeResponse(apiJson) {
  const raw = apiJson?.content?.[0]?.text;
  if (!raw) throw new Error('Empty content field in Claude API response');
  const cleaned = raw
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/\s*```\s*$/, '')
    .trim();
  return JSON.parse(cleaned);
}

const visionApiJson = $('Claude Vision API').first().json;
const scriptApiJson = $('Claude Text API').first().json;
const ctx           = $('Build Vision Payload').first().json;
const sheetsRow     = $('Read Pending Rows').first().json;

const errors = [];
let visual_vars = {};
let script_vars = {};

try {
  visual_vars = parseClaudeResponse(visionApiJson);
} catch (e) {
  errors.push('vision_parse_error: ' + e.message);
}

try {
  script_vars = parseClaudeResponse(scriptApiJson);
} catch (e) {
  errors.push('script_parse_error: ' + e.message);
}

const merged = {
  ad_id:            ctx.ad_id,
  duration_seconds: ctx.duration,
  frame_count:      ctx.frame_count,
  processed_at:     new Date().toISOString(),
  hook_type:             visual_vars.hook_type             ?? null,
  face_in_hook:          visual_vars.face_in_hook          ?? null,
  eye_contact_in_hook:   visual_vars.eye_contact_in_hook   ?? null,
  scene_setup:           visual_vars.scene_setup           ?? null,
  subtitle_present:      visual_vars.subtitle_present      ?? null,
  emotional_tone:        script_vars.emotional_tone        ?? null,
  hook_addresses_pain:   script_vars.hook_addresses_pain   ?? null,
  cta_type:              script_vars.cta_type              ?? null,
  social_proof_present:  script_vars.social_proof_present  ?? null,
  language_primary:      script_vars.language_primary      ?? null,
};

const ALLOWED = {
  hook_type:           ['question', 'bold_statement', 'person_speaking', 'text_only', 'visual_shock'],
  face_in_hook:        [true, false],
  eye_contact_in_hook: [true, false],
  scene_setup:         ['person_to_cam', 'skit', 'skit_p2c', 'b_roll', 'b_roll_long'],
  subtitle_present:    [true, false],
  emotional_tone:      ['urgency', 'aspiration', 'humor', 'trust', 'empathy', 'fear'],
  hook_addresses_pain: [true, false],
  cta_type:            ['check_score_free', 'check_score', 'download_app', 'call_now', 'visit_website', 'none'],
  social_proof_present:[true, false],
  language_primary:    ['hindi', 'english', 'hinglish'],
};

for (const [field, allowed] of Object.entries(ALLOWED)) {
  const val = merged[field];
  if (val === null) continue;
  if (val === undefined) {
    errors.push(field + ': missing from Claude response');
  } else if (!allowed.includes(val)) {
    errors.push(field + ': unexpected value "' + val + '" (allowed: ' + allowed.join(', ') + ')');
  }
}

merged.status       = errors.length > 0 ? 'error' : 'done';
merged.error_detail = errors.join(' | ');
merged.row_number   = sheetsRow.row_number;

return [{ json: merged }];
